export interface Animation {
    id: string;
    duration: number;
    elapsed: number;
    from: number;
    to: number;
    easing: (t: number) => number;
    onUpdate: (value: number) => void;
    onComplete?: () => void;
    loop: boolean;
    active: boolean;
}

export type EasingFunction = (t: number) => number;

export class AnimationSystem {
    private engine: unknown;
    private animations: Map<string, Animation> = new Map();
    private initialized: boolean = false;

    static easings: Record<string, EasingFunction> = {
        linear: (t: number) => t,
        easeInQuad: (t: number) => t * t,
        easeOutQuad: (t: number) => t * (2 - t),
        easeInOutQuad: (t: number) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t,
        easeInCubic: (t: number) => t * t * t,
        easeOutCubic: (t: number) => (--t) * t * t + 1,
        easeInOutCubic: (t: number) => t < 0.5 ? 4 * t * t * t : (t - 1) * (2 * t - 2) * (2 * t - 2) + 1,
        easeInElastic: (t: number) => {
            if (t === 0 || t === 1) return t;
            return -Math.pow(2, 10 * (t - 1)) * Math.sin((t - 1.1) * 5 * Math.PI);
        },
        easeOutElastic: (t: number) => {
            if (t === 0 || t === 1) return t;
            return Math.pow(2, -10 * t) * Math.sin((t - 0.1) * 5 * Math.PI) + 1;
        },
        easeOutBounce: (t: number) => {
            if (t < 1 / 2.75) {
                return 7.5625 * t * t;
            } else if (t < 2 / 2.75) {
                return 7.5625 * (t -= 1.5 / 2.75) * t + 0.75;
            } else if (t < 2.5 / 2.75) {
                return 7.5625 * (t -= 2.25 / 2.75) * t + 0.9375;
            } else {
                return 7.5625 * (t -= 2.625 / 2.75) * t + 0.984375;
            }
        }
    };

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async initialize(): Promise<void> {
        console.log('🎬 AnimationSystem 初始化...');
        this.initialized = true;
        console.log('✅ AnimationSystem 初始化完成');
    }

    animate(
        id: string,
        from: number,
        to: number,
        duration: number,
        onUpdate: (value: number) => void,
        options?: {
            easing?: string | EasingFunction;
            onComplete?: () => void;
            loop?: boolean;
        }
    ): Animation {
        const easingFn = typeof options?.easing === 'function'
            ? options.easing
            : AnimationSystem.easings[options?.easing ?? 'linear'] ?? AnimationSystem.easings.linear;

        const animation: Animation = {
            id,
            duration,
            elapsed: 0,
            from,
            to,
            easing: easingFn,
            onUpdate,
            onComplete: options?.onComplete,
            loop: options?.loop ?? false,
            active: true
        };

        this.animations.set(id, animation);
        return animation;
    }

    fade(
        id: string,
        element: HTMLElement,
        from: number,
        to: number,
        duration: number,
        onComplete?: () => void
    ): Animation {
        return this.animate(
            id,
            from,
            to,
            duration,
            (value) => {
                element.style.opacity = String(value);
            },
            { easing: 'easeInOutQuad', onComplete }
        );
    }

    move(
        id: string,
        element: HTMLElement,
        fromX: number,
        fromY: number,
        toX: number,
        toY: number,
        duration: number,
        easing: string = 'easeOutQuad'
    ): Animation {
        return this.animate(
            id,
            0,
            1,
            duration,
            (value) => {
                const x = fromX + (toX - fromX) * value;
                const y = fromY + (toY - fromY) * value;
                element.style.transform = `translate(${x}px, ${y}px)`;
            },
            { easing }
        );
    }

    scale(
        id: string,
        element: HTMLElement,
        from: number,
        to: number,
        duration: number
    ): Animation {
        return this.animate(
            id,
            from,
            to,
            duration,
            (value) => {
                element.style.transform = `scale(${value})`;
            },
            { easing: 'easeOutElastic' }
        );
    }

    update(deltaTime: number): void {
        for (const [id, anim] of this.animations) {
            if (!anim.active) {
                this.animations.delete(id);
                continue;
            }

            anim.elapsed += deltaTime;
            const progress = Math.min(anim.elapsed / anim.duration, 1);
            const easedProgress = anim.easing(progress);
            const value = anim.from + (anim.to - anim.from) * easedProgress;

            anim.onUpdate(value);

            if (progress >= 1) {
                if (anim.loop) {
                    anim.elapsed = 0;
                } else {
                    anim.active = false;
                    anim.onComplete?.();
                    this.animations.delete(id);
                }
            }
        }
    }

    stop(id: string): void {
        const anim = this.animations.get(id);
        if (anim) {
            anim.active = false;
            this.animations.delete(id);
        }
    }

    pause(id: string): void {
        const anim = this.animations.get(id);
        if (anim) {
            anim.active = false;
        }
    }

    resume(id: string): void {
        const anim = this.animations.get(id);
        if (anim) {
            anim.active = true;
        }
    }

    stopAll(): void {
        this.animations.clear();
    }

    destroy(): void {
        this.animations.clear();
        this.initialized = false;
    }
}

export default AnimationSystem;
